import{_ as t,o,c as a,a3 as i}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.AI","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/ai.md","filePath":"cosmos/framework/packages/ai.md","lastUpdated":1783216089000}'),r={name:"cosmos/framework/packages/ai.md"};function d(s,e,n,l,c,h){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="xihan-framework-ai" tabindex="-1">XiHan.Framework.AI <a class="header-anchor" href="#xihan-framework-ai" aria-label="Permalink to &quot;XiHan.Framework.AI&quot;">​</a></h1><blockquote><p>AI 集成：Semantic Kernel、智能代理、MCP 协议支持</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.AI</code></li><li><strong>模块类</strong>：<code>XiHanAIModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>这个包是 AI 抽象（<code>XiHan.Framework.AI.Abstractions</code>）的默认实现，基于 <code>Microsoft.Extensions.AI</code> 与 Microsoft Agent Framework 提供开箱即用的会话、Agent、嵌入与 RAG 能力。它统一了「多 provider 选择」与「配置热切换」，并能把应用注册的技能通过 MCP（Model Context Protocol）暴露给外部 AI 客户端（如 Claude Code / Cursor）。多数 provider（OpenAI / DeepSeek / Ollama / vLLM 等）走 OpenAI 兼容协议，一个适配器即可覆盖。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要以统一门面调用大模型（一次对话 / 流式对话），并按 provider 名切换厂商</li><li>需要基于 provider 的嵌入生成 + RAG 检索增强（切片 / 摄取 / 检索 / 提示增强）</li><li>想构建带工具调用与多轮记忆的智能代理（Agent）</li><li>想把应用侧「技能」暴露为 MCP tools，供外部 AI 客户端调用</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.AI</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanAIModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>ConfigureServices</code> 里调用 <code>AddXiHanAI</code> 与 <code>AddXiHanRAG</code>，注册 provider 配置源、解析器、会话门面、技能注册表、Agent 工厂与 RAG 默认实现。所有服务均以 <code>TryAdd*</code> 注册，应用层可覆盖任一默认项（如换成读数据库的 provider 配置源）。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>会话门面实现</strong>：<code>XiHanAiService</code> 实现 <code>IXiHanAiService</code>，薄封装 M.E.AI 的 <code>IChatClient</code>——选 provider 后透传，工具调用 / 结构化输出 / 遥测缓存中间件走原生</li><li><strong>多 provider 解析 + 热切换</strong>：<code>AiChatClientResolver</code> / <code>AiEmbeddingGeneratorResolver</code> 按 provider 名构建并缓存客户端，<code>Invalidate</code> 使缓存失效以实现配置热切换</li><li><strong>OpenAI 兼容适配</strong>：<code>OpenAiCompatibleChatClientFactory</code> / <code>OpenAiEmbeddingGeneratorFactory</code> 用一套 OpenAI 兼容工厂覆盖 OpenAI / DeepSeek / Ollama / vLLM 等端点</li><li><strong>可插拔配置源</strong>：默认 <code>OptionsAiProviderConfigStore</code> 读 <code>XiHan:AI</code> 配置节兜底；应用层可换 DB store 实现 store 化配置</li><li><strong>智能代理</strong>：<code>XiHanAgentFactory</code> 基于 Microsoft Agent Framework 从 provider 解析器构建 <code>AIAgent</code>，支持工具与多轮会话</li><li><strong>RAG 默认实现</strong>：<code>FixedWindowChunkingStrategy</code>（固定窗口切片）、<code>DefaultKnowledgeIngestor</code>（摄取）、<code>DefaultKnowledgeRetriever</code>（检索）、<code>DefaultRagPromptAugmenter</code>（提示增强）</li><li><strong>MCP 工具桥接</strong>：<code>AddXiHanMcpServerTools</code> 把技能注册表投影为 MCP server tools，配合官方 <code>AddMcpServer()</code> 使用</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>XiHanAiService</code></td><td><code>IXiHanAiService</code> 默认实现（选 provider → 透传 M.E.AI）</td></tr><tr><td><code>AiChatClientResolver</code> / <code>AiEmbeddingGeneratorResolver</code></td><td>多 provider 解析器（含缓存与 <code>Invalidate</code> 热切换）</td></tr><tr><td><code>OpenAiCompatibleChatClientFactory</code></td><td>OpenAI 兼容会话客户端工厂</td></tr><tr><td><code>OpenAiEmbeddingGeneratorFactory</code></td><td>OpenAI 兼容嵌入生成器工厂</td></tr><tr><td><code>OptionsAiProviderConfigStore</code></td><td>默认 provider 配置源（读 <code>XiHan:AI</code> 配置节）</td></tr><tr><td><code>XiHanAgentFactory</code></td><td>Microsoft Agent Framework 的 <code>AIAgent</code> 工厂</td></tr><tr><td><code>DefaultAiSkillRegistry</code></td><td>技能注册表默认实现</td></tr><tr><td><code>SkillMcpToolsConfigurator</code></td><td>把技能投影为 MCP server tools</td></tr><tr><td><code>FixedWindowChunkingStrategy</code> / <code>DefaultKnowledgeIngestor</code> / <code>DefaultKnowledgeRetriever</code> / <code>DefaultRagPromptAugmenter</code></td><td>RAG 切片 / 摄取 / 检索 / 提示增强默认实现</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li><a href="./ai-abstractions">XiHan.Framework.AI.Abstractions</a>（接口与契约）</li><li><a href="./core">XiHan.Framework.Core</a></li><li><a href="./http">XiHan.Framework.Http</a>（<code>XiHanAIModule</code> 依赖 <code>XiHanHttpModule</code>）</li><li>第三方核心：<strong>Microsoft.Extensions.AI</strong> / <strong>Microsoft.Extensions.AI.OpenAI</strong>（会话与嵌入）、<strong>Microsoft.Agents.AI</strong>（Agent）、<strong>ModelContextProtocol</strong>（MCP）、<strong>Microsoft.Extensions.VectorData.Abstractions</strong>（向量数据）</li></ul><div class="tip custom-block"><p class="custom-block-title">部署提示</p><p>本包不注册具体 <code>VectorStore</code>——向量连接器（如 Qdrant）与嵌入模型选择属部署事项，由应用层登记（如 <code>AddQdrantVectorStore</code>）。</p></div><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./ai-abstractions">XiHan.Framework.AI.Abstractions</a></li><li><a href="./http">XiHan.Framework.Http</a></li></ul>`,21)])])}const g=t(r,[["render",d]]);export{k as __pageData,g as default};
